+                rows.iter().any(|(id, _, _)| *id == expected_id),
+                "missing row id={expected_id} (thread={tid}, offset={i})"
+            );
+        }
+    }
+
+    assert_eq!(rows.len(), n_threads * ops_per_thread);
+}

